import React, { useEffect, useRef, useState, useCallback } from "react";

const SEGMENT_COLORS = [
  { label: "W",  color: "#f44336", textColor: "#fff" },
  { label: "0",  color: "#607d8b", textColor: "#fff" },
  { label: "1",  color: "#2196f3", textColor: "#fff" },
  { label: "2",  color: "#4caf50", textColor: "#fff" },
  { label: "3",  color: "#9c27b0", textColor: "#fff" },
  { label: "4",  color: "#ff9800", textColor: "#fff" },
  { label: "6",  color: "#ffc107", textColor: "#000" },
];

const PROBABILITIES = {
  aggressive: [0.40, 0.10, 0.10, 0.10, 0.05, 0.10, 0.15],
  defensive:  [0.20, 0.30, 0.20, 0.10, 0.05, 0.10, 0.05],
};

function PowerBar({ styleType, onShot, disabled }) {
  // pos goes 0 → 1 → 0 → 1 (bouncing)
  const [pos, setPos] = useState(0);
  const dirRef = useRef(1);
  const posRef = useRef(0);
  const rafRef = useRef(null);
  const lastTime = useRef(null);
  const SPEED = 0.55; // units per second (full bar = 1)

  // Animate slider with requestAnimationFrame for smoothness
  useEffect(() => {
    if (disabled) {
      cancelAnimationFrame(rafRef.current);
      return;
    }
    const animate = (timestamp) => {
      if (lastTime.current === null) lastTime.current = timestamp;
      const delta = (timestamp - lastTime.current) / 1000;
      lastTime.current = timestamp;

      let newPos = posRef.current + dirRef.current * SPEED * delta;
      if (newPos >= 1) {
        newPos = 1;
        dirRef.current = -1;
      } else if (newPos <= 0) {
        newPos = 0;
        dirRef.current = 1;
      }
      posRef.current = newPos;
      setPos(newPos);
      rafRef.current = requestAnimationFrame(animate);
    };
    lastTime.current = null;
    rafRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(rafRef.current);
  }, [disabled]);

  const handleShot = useCallback(() => {
    if (disabled) return;
    onShot(posRef.current);
  }, [disabled, onShot]);

  // Keyboard support
  useEffect(() => {
    const handler = (e) => {
      if ((e.code === "Space" || e.code === "Enter") && !disabled) {
        e.preventDefault();
        handleShot();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [handleShot, disabled]);

  const probs = PROBABILITIES[styleType];

  // Which segment is the slider currently in?
  let activeSegment = -1;
  let cumulative = 0;
  for (let i = 0; i < probs.length; i++) {
    cumulative += probs[i];
    if (pos <= cumulative) { activeSegment = i; break; }
  }

  return (
    <div className="powerbar-container">
      <div className="powerbar-legend">
        {SEGMENT_COLORS.map((seg, i) => (
          <div key={i} className={`legend-item ${activeSegment === i ? "legend-active" : ""}`}>
            <div className="legend-swatch" style={{ background: seg.color }} />
            <span style={{ color: seg.textColor === "#fff" ? "#ccc" : "#ffecb3" }}>
              {seg.label === "W" ? "Wicket" : `${seg.label} run${seg.label === "1" ? "" : "s"}`}
              {" "}({(probs[i] * 100).toFixed(0)}%)
            </span>
          </div>
        ))}
      </div>

      <div className="powerbar-track-wrapper">
        <div className="powerbar-track">
          {probs.map((p, i) => (
            <div
              key={i}
              className={`powerbar-segment ${activeSegment === i ? "segment-active" : ""}`}
              style={{
                width: `${p * 100}%`,
                background: SEGMENT_COLORS[i].color,
              }}
            >
              <span
                className="segment-label"
                style={{ color: SEGMENT_COLORS[i].textColor }}
              >
                {SEGMENT_COLORS[i].label}
              </span>
            </div>
          ))}
          {/* Slider needle */}
          <div
            className="slider-needle"
            style={{ left: `${pos * 100}%` }}
          />
        </div>
      </div>

      <div className="shot-btn-row">
        <button
          className="shot-btn"
          onClick={handleShot}
          disabled={disabled}
        >
          {disabled ? "⏳ Wait..." : "🏏 Play Shot  [Space]"}
        </button>
      </div>
    </div>
  );
}

export default PowerBar;
